import type { ApiResponse } from '../types';

// Use environment variable for production, or proxy in development
const API_BASE = import.meta.env.VITE_API_URL
  ? `${import.meta.env.VITE_API_URL}/api`
  : '/api';

// Log API configuration on startup
console.log('[API] VITE_API_URL:', import.meta.env.VITE_API_URL || '(not set, using proxy)');
console.log('[API] API_BASE:', API_BASE);

// Token storage for Safari/incognito fallback (when cookies don't work)
// Uses sessionStorage instead of localStorage to limit exposure to current tab
const TOKEN_KEY = 'dev_dash_auth_token';

export function setAuthToken(token: string): void {
  sessionStorage.setItem(TOKEN_KEY, token);
  // Clean up any legacy localStorage token
  localStorage.removeItem(TOKEN_KEY);
}

export function clearAuthToken(): void {
  sessionStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(TOKEN_KEY);
}

export function getAuthToken(): string | null {
  // Check sessionStorage first, fall back to localStorage for migration
  return sessionStorage.getItem(TOKEN_KEY) || localStorage.getItem(TOKEN_KEY);
}

