// Multi-origin CORS: allow satellite apps (DD Red, Yellow, Violet) via ALLOWED_ORIGINS
// Supports exact URLs and wildcard patterns like *.vercel.app for preview deploys
const allowedOrigins: string[] = [clientUrl];
if (process.env.ALLOWED_ORIGINS) {
  allowedOrigins.push(...process.env.ALLOWED_ORIGINS.split(',').map(s => s.trim()));
}

function isOriginAllowed(origin: string | undefined): boolean {
  if (!origin) return false;
  for (const allowed of allowedOrigins) {
    if (allowed === origin) return true;
    // Wildcard pattern: "*.vercel.app" matches any subdomain
    if (allowed.startsWith('*.')) {
      const suffix = allowed.slice(1); // ".vercel.app"
      if (origin.endsWith(suffix) && origin.includes('://')) return true;
    }
  }
  return false;
}

const corsOriginFn = (origin: string | undefined, callback: (err: Error | null, allow?: boolean) => void) => {
  // No-origin requests (server-to-server, curl, CLI) are allowed through CORS.
  // Cookie-auth CSRF is mitigated by the X-Requested-With header requirement (see CSRF middleware).
  if (!origin || isOriginAllowed(origin)) {
    callback(null, true);
  } else {
    callback(null, false);
  }
};

// Socket.io setup
const io = new SocketServer(httpServer, {
  cors: {
    origin: corsOriginFn,
    credentials: true,
  },
});

// Request timing (opt-in via REQUEST_TIMING=1, always on in test)
app.use(requestTiming);

// Security headers
app.use(helmet({
  contentSecurityPolicy: false, // CSP managed per-route as needed
  crossOriginEmbedderPolicy: false, // Allow cross-origin resource loading
}));

